noncompliant:
#include <stdio.h>

FILE *create_temp_file() {
    char filename[L_tmpnam];
    tmpnam(filename); // Noncompliant: race condition vulnerability
    return fopen(filename, "w");
}

// Also noncompliant:
char *get_temp_name() {
    return tmpnam(NULL); // Noncompliant: same security issue
}

compliant:
#include <stdio.h>
#include <stdlib.h>

FILE *create_secure_temp() {
    char template[] = "/tmp/myapp_XXXXXX";
    int fd = mkstemp(template); // Compliant: atomically creates and opens
    return fdopen(fd, "w+");
}

// Alternative using tmpfile():
FILE *create_anonymous_temp() {
    return tmpfile(); // Compliant: creates anonymous temp file
}
